import{_ as e,o as t,c as r,ag as o}from"./chunks/framework.C9sp7nFj.js";const _=JSON.parse('{"title":"国际航班选座技巧","description":"长途国际航班选座攻略和舒适出行技巧","frontmatter":{"title":"国际航班选座技巧","description":"长途国际航班选座攻略和舒适出行技巧"},"headers":[],"relativePath":"knowledge/flights/seat-tips.md","filePath":"knowledge/flights/seat-tips.md","lastUpdated":null}'),i={name:"knowledge/flights/seat-tips.md"};function s(l,a,n,d,h,p){return t(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="国际航班选座技巧" tabindex="-1">国际航班选座技巧 <a class="header-anchor" href="#国际航班选座技巧" aria-label="Permalink to &quot;国际航班选座技巧&quot;">​</a></h1><h2 id="座位类型选择" tabindex="-1">座位类型选择 <a class="header-anchor" href="#座位类型选择" aria-label="Permalink to &quot;座位类型选择&quot;">​</a></h2><p>靠窗座位适合喜欢安静和欣赏风景的乘客，走道座位方便起身活动。中间座位是最不推荐的选择。</p><h2 id="最佳座位推荐" tabindex="-1">最佳座位推荐 <a class="header-anchor" href="#最佳座位推荐" aria-label="Permalink to &quot;最佳座位推荐&quot;">​</a></h2><p>紧急出口排的座位腿部空间最大，但需满足航空公司的身体条件要求。前排座位上下机方便但可能需额外付费。</p><h2 id="选座注意事项" tabindex="-1">选座注意事项 <a class="header-anchor" href="#选座注意事项" aria-label="Permalink to &quot;选座注意事项&quot;">​</a></h2><p>部分航空公司提前选座需要额外付费。建议在值机开放后第一时间在线值机，免费获得心仪座位。</p><h2 id="特殊需求座位" tabindex="-1">特殊需求座位 <a class="header-anchor" href="#特殊需求座位" aria-label="Permalink to &quot;特殊需求座位&quot;">​</a></h2><p>携带婴儿的乘客可选择前排有婴儿摇篮挂点的座位。行动不便的乘客可申请靠近洗手间的座位。</p>',9)])])}const f=e(i,[["render",s]]);export{_ as __pageData,f as default};
